// nodes/noteNode.js
import { useState } from 'react';
import { BaseNode, fieldStyle } from './BaseNode';
import { useStore } from '../store';

export const NoteNode = ({ id, data }) => {
  const updateNodeField = useStore((s) => s.updateNodeField);
  const [note, setNote] = useState(data?.note ?? 'Add a note…');

  return (
    <BaseNode
      id={id}
      title="Note"
      icon="📝"
      accentColor="#fbbf24"
      inputs={[]}
      outputs={[]}
      minWidth={200}
      style={{ opacity: 0.9 }}
    >
      <textarea
        style={{
          ...fieldStyle.input,
          resize: 'vertical',
          minHeight: '70px',
          lineHeight: 1.6,
          fontSize: '12px',
          color: '#fde68a',
          background: 'rgba(251,191,36,0.07)',
        }}
        value={note}
        onChange={(e) => {
          setNote(e.target.value);
          updateNodeField(id, 'note', e.target.value);
        }}
      />
    </BaseNode>
  );
};
